import React, { useState } from "react";

export default function AddExpense({
  type,
  travelForm,
  ticketForm,
  setTravelForm,
  setTicketForm,
  submitTravel,
  submitTicket,
  travelExpenses,
  ticketExpenses,
  deleteExpense,
  editExpense,
}) {
  const isTravel = type === "travel";
  const isTicket = type === "ticket";

  const [month, setMonth] = useState("");

  // FILTER BY MONTH
  const filteredData = (isTravel ? travelExpenses : ticketExpenses).filter(
    (item) => {
      if (!month) return true;
      const date = new Date(item.travel_date || item.ticket_date);
      const selected = new Date(month);
      return (
        date.getMonth() === selected.getMonth() &&
        date.getFullYear() === selected.getFullYear()
      );
    }
  );

  return (
    <div style={{ padding: "20px" }}>
      <h2 style={{ color: "#0f9d58" }}>
        {isTravel ? "Add Travel Expense" : "Add Ticket Expense"}
      </h2>

      {/* FORM */}
      <form
        onSubmit={isTravel ? submitTravel : submitTicket}
        style={{
          background: "#fbfff9",
          padding: "20px",
          borderRadius: "10px",
          width: "400px",
        }}
      >
        <input
          type="date"
          required
          style={input}
          value={isTravel ? travelForm.travel_date : ticketForm.ticket_date}
          onChange={(e) =>
            isTravel
              ? setTravelForm({ ...travelForm, travel_date: e.target.value })
              : setTicketForm({ ...ticketForm, ticket_date: e.target.value })
          }
        />

        <input
          placeholder="Purpose"
          required
          style={input}
          value={isTravel ? travelForm.purpose : ticketForm.purpose}
          onChange={(e) =>
            isTravel
              ? setTravelForm({ ...travelForm, purpose: e.target.value })
              : setTicketForm({ ...ticketForm, purpose: e.target.value })
          }
        />

        <input
          placeholder="Amount"
          type="number"
          required
          style={input}
          value={isTravel ? travelForm.amount : ticketForm.amount}
          onChange={(e) =>
            isTravel
              ? setTravelForm({ ...travelForm, amount: e.target.value })
              : setTicketForm({ ...ticketForm, amount: e.target.value })
          }
        />

        {/* TRAVEL ONLY FIELDS */}
        {isTravel && (
          <>
            <input
              placeholder="From"
              style={input}
              value={travelForm.location_from}
              onChange={(e) =>
                setTravelForm({
                  ...travelForm,
                  location_from: e.target.value,
                })
              }
            />

            <input
              placeholder="To"
              style={input}
              value={travelForm.location_to}
              onChange={(e) =>
                setTravelForm({
                  ...travelForm,
                  location_to: e.target.value,
                })
              }
            />
          </>
        )}

        {/* TICKET ONLY */}
        {isTicket && (
          <input
            placeholder="Assigned To"
            style={input}
            value={ticketForm.assigned_to}
            onChange={(e) =>
              setTicketForm({ ...ticketForm, assigned_to: e.target.value })
            }
          />
        )}

        <button type="submit" style={buttonPrimary}>
          Submit
        </button>
      </form>

      {/* MONTH FILTER */}
      <div style={{ marginTop: "20px" }}>
        <h3 style={{ color: "#0f9d58" }}>Filter by Month</h3>
        <input
          type="month"
          style={input}
          value={month}
          onChange={(e) => setMonth(e.target.value)}
        />
      </div>

      {/* HISTORY TABLE */}
      <h3 style={{ color: "#0f9d58", marginTop: "20px" }}>
        {isTravel ? "Travel History" : "Ticket History"}
      </h3>

      <table style={table}>
        <thead>
          <tr>
            <th>Date</th>
            <th>Purpose</th>
            <th>Amount</th>
            <th>Status</th>
            <th>Edit</th>
            <th>Delete</th>
          </tr>
        </thead>

        <tbody>
          {filteredData.map((item) => (
            <tr key={item.travel_id || item.ticket_id}>
              <td>{item.travel_date || item.ticket_date}</td>
              <td>{item.purpose}</td>
              <td>₹{item.amount}</td>
              <td>{item.approval_status || item.status}</td>

              <td>
                <button
                  onClick={() => editExpense(item)}
                  style={editBtn}
                >
                  Edit
                </button>
              </td>

              <td>
                <button
                  onClick={() =>
                    deleteExpense(item.travel_id || item.ticket_id)
                  }
                  style={deleteBtn}
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

// STYLE OBJECTS
const input = {
  width: "100%",
  padding: "10px",
  marginBottom: "10px",
  borderRadius: "8px",
  border: "1px solid #ccc",
};

const buttonPrimary = {
  background: "#0f9d58",
  color: "white",
  padding: "10px",
  border: "none",
  width: "100%",
  borderRadius: "8px",
  cursor: "pointer",
  marginTop: "10px",
};

const table = {
  width: "100%",
  marginTop: "20px",
  borderCollapse: "collapse",
};

const editBtn = {
  background: "#ffc107",
  padding: "6px 10px",
  border: "none",
  borderRadius: "5px",
  cursor: "pointer",
};

const deleteBtn = {
  background: "#dc3545",
  padding: "6px 10px",
  border: "none",
  borderRadius: "5px",
  color: "white",
  cursor: "pointer",
};
